async (params, browser) => {
  // Open directions
  await browser.open(`https://www.google.com/maps/dir/${params.origin}/${params.destination}`)

  // Wait for directions to load
  await browser.waitForSelector('div[role=\'list\'], div[data-trip-index=\'0\'], .directions-mode-group', 15000)

  // Let directions calculate
  await browser.wait(3000)

  // Extract directions
  const directions = await browser.evaluate(`const main = document.querySelector('[role="main"]'); const allText = main ? main.innerText : ''; const distMatch = allText.match(/(\d[\d.,]+\s*(?:km|mi|miles|m|ft))/i); const durMatch = allText.match(/(\d+\s*(?:h(?:ours?)?|min(?:utes?)?|hr)[\s\d]*(?:min(?:utes?)?)?)/i); const steps = []; const stepEls = document.querySelectorAll('div[data-step-index], div[role="list"] div[role="listitem"], .directions-mode-step'); stepEls.forEach((step, i) => { if (i >= 15) return; const t = step.textContent.trim(); if (t.length > 2) steps.push(t); }); if (steps.length === 0) { const listItems = document.querySelectorAll('div[role="list"] > div'); listItems.forEach((item, i) => { if (i >= 15) return; const t = item.textContent.trim(); if (t.length > 5) steps.push(t); }); } return { distance: distMatch ? distMatch[1] : '', duration: durMatch ? durMatch[1] : '', steps: steps, url: window.location.href }`)

  return directions
}
